Content of res://systems/state_machine.gd:
class_name StateMachine
extends Node

@export var initial_state: Node

var current_state: Node
var states: Dictionary = {}

func _ready() -> void:
	# 直接初始化，不使用 await（避免 coroutine 被 GC）
	for child in get_children():
		var has_state_class = child is State
		print("   - 子节点: ", child.name, ", 脚本: ", child.get_script(), ", is State: ", has_state_class)
		if has_state_class:
			states[child.name.to_lower()] = child
			child.transitioned.connect(on_child_transition)
			child.entity = owner
			print("     ✅ 已注册状态: ", child.name)

	if initial_state:
		current_state = initial_state
		print("🔍 StateMachine: 使用 initial_state: ", current_state.name)
	else:
		# 自动使用第一个 State 子节点作为初始状态
		for child in get_children():
			if child is State:
				current_state = child
				print("🔍 StateMachine: 自动使用首个状态: ", current_state.name)
				break

	if not current_state:
		print("❌ StateMachine: 没有找到任何状态！")
		return

	if current_state:
		current_state.enter()
		print("🔍 StateMachine: 已进入初始状态: ", current_state.name)

	# 确保 Camera2D 是当前相机
	var cam = owner.get_node_or_null("Camera2D") if owner else null
	if cam and cam is Camera2D:
		cam.enabled = true

func _process(delta: float) -> void:
	if current_state:
		current_state.update(delta)

func _physics_process(delta: float) -> void:
	if current_state:
		current_state.physics_update(delta)

func on_child_transition(state: Node, new_state_name: String) -> void:
	if state != current_state:
		return

	var new_state = states.get(new_state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % new_state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state

## 强制切换到指定状态（用于外部触发）
func transition_to(state_name: String) -> void:
	var new_state = states.get(state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state

Content of res://skills/fireball.gd:
extends Area2D
class_name Fireball

@export var speed: float = 500.0
@export var damage: int = 25
@export var lifetime: float = 3.0

var direction: Vector2 = Vector2.DOWN

func _ready() -> void:
	# 确保碰撞形状有效
	var shape_node = $CollisionShape2D
	if shape_node and shape_node.shape == null:
		var circle = CircleShape2D.new()
		circle.radius = 8.0
		shape_node.shape = circle

	# 连接信号 - 碰撞到物体时
	body_entered.connect(_on_body_entered)
	area_entered.connect(_on_area_entered)

	# 自动销毁
	await get_tree().create_timer(lifetime).timeout
	queue_free()

func set_direction(dir: Vector2) -> void:
	direction = dir.normalized()
	rotation = direction.angle()

func _physics_process(delta: float) -> void:
	global_position += direction * speed * delta

func _on_body_entered(body: Node2D) -> void:
	if body.has_method("take_damage"):
		body.take_damage(damage)
	queue_free()

func _on_area_entered(area: Area2D) -> void:
	if area.has_method("take_damage"):
		area.take_damage(damage)
	queue_free()

Content of res://test_validation.gd:
extends Node
## 项目修复验证脚本 —— 在编辑器中运行此脚本检查核心功能
## 使用方式: main.tscn 中临时挂载此脚本，运行游戏查看输出

const SEPARATOR = "=================================================="

func _ready() -> void:
	print(SEPARATOR)
	print("🔍 项目健康验证报告")
	print(SEPARATOR)

	_validate_main_scene()
	_validate_player()
	_validate_state_machine()
	_validate_skills()
	_validate_input()

	print(SEPARATOR)
	print("✅ 验证完成！窗口将在 5 秒后自动关闭...")
	print(SEPARATOR)

	# 等待 5 秒让用户看清输出再退出
	await get_tree().create_timer(5.0).timeout
	get_tree().quit()

func _validate_main_scene() -> void:
	print("\n--- 主场景验证 ---")
	var game = get_tree().current_scene
	if game and game.name == "Game":
		print("✅ main.tscn 根节点 'Game' 存在")
	else:
		print("❌ main.tscn 根节点异常")

	var overworld = game.get_node_or_null("Overworld")
	print("✅ Overworld 场景: %s" % ["存在" if overworld else "缺失"])

	var player = game.get_node_or_null("Player")
	print("✅ Player 节点: %s" % ["存在" if player else "缺失"])

func _validate_player() -> void:
	print("\n--- Player 验证 ---")
	var player = get_tree().current_scene.get_node_or_null("Player")
	if not player:
		print("❌ 找不到 Player 节点")
		return

	# 检查关键方法是否存在
	var methods_to_check = ["perform_melee_attack", "cast_skill", "get_mouse_direction"]
	for method in methods_to_check:
		if player.has_method(method):
			print("✅ 方法 '%s()' 存在" % method)
		else:
			print("❌ 方法 '%s()' 缺失 —— 运行时会崩溃！" % method)

	# 检查关键属性
	if "move_speed" in player:
		print("✅ 属性 move_speed = %s" % player.move_speed)
	if "attack_damage" in player:
		print("✅ 属性 attack_damage = %s" % player.attack_damage)
	if "skill_scene" in player:
		print("✅ 属性 skill_scene = %s" % ("已设置" if player.skill_scene else "未设置"))

	# 检查子节点
	var children = ["Sprite2D", "CollisionShape2D", "Camera2D", "AnimationPlayer", "AttackHitbox", "StateMachine"]
	for child_name in children:
		if player.get_node_or_null(child_name):
			print("✅ 子节点 '%s' 存在" % child_name)
		else:
			print("❌ 子节点 '%s' 缺失" % child_name)

func _validate_state_machine() -> void:
	print("\n--- StateMachine 验证 ---")
	var player = get_tree().current_scene.get_node_or_null("Player")
	if not player:
		return

	var sm = player.get_node_or_null("StateMachine")
	if not sm:
		print("❌ StateMachine 节点缺失")
		return
	print("✅ StateMachine 节点存在")

	# 检查 initial_state
	if sm.get("initial_state") != null:
		print("✅ initial_state 已设置: %s" % sm.initial_state.name if sm.initial_state else "null")
	else:
		print("⚠️ initial_state 未设置（将使用自动回退）")

	# 检查所有状态子节点
	var expected_states = ["Idle", "Move", "Attack", "Dodge", "Skill"]
	for state_name in expected_states:
		var state = sm.get_node_or_null(state_name)
		if state:
			var script_path = state.get_script().resource_path if state.get_script() else "无脚本"
			print("✅ 状态 '%s' 存在 [脚本: %s]" % [state_name, script_path])
		else:
			print("❌ 状态 '%s' 缺失" % state_name)

func _validate_skills() -> void:
	print("\n--- 技能验证 ---")
	var fireball = load("res://skills/fireball.tscn")
	if fireball:
		print("✅ fireball.tscn 可加载")
		var instance = fireball.instantiate()
		if instance is Area2D:
			print("✅ fireball 根节点类型为 Area2D")
		if instance.has_method("set_direction"):
			print("✅ fireball 拥有 set_direction() 方法")
		if instance.has_signal("body_entered"):
			print("✅ fireball 拥有 body_entered 信号")
		instance.queue_free()
	else:
		print("❌ fireball.tscn 无法加载")

func _validate_input() -> void:
	print("\n--- 输入映射验证 ---")
	var actions = ["move_left", "move_right", "move_up", "move_down", "attack", "dodge", "skill"]
	for action in actions:
		if InputMap.has_action(action):
			print("✅ 输入动作 '%s' 已注册" % action)
		else:
			print("❌ 输入动作 '%s' 未注册 —— 将无法操作！" % action)

Content of res://entities/player/player.gd:
extends CharacterBody2D
class_name Player

## 移动参数
@export var move_speed: float = 300.0

## 攻击参数
@export var attack_range: float = 40.0
@export var attack_damage: int = 10

## 技能参数
@export var skill_scene: PackedScene

## 当前朝向
var facing_direction: Vector2 = Vector2.DOWN

## 引用
@onready var sprite: Sprite2D = $Sprite2D
@onready var collision_shape: CollisionShape2D = $CollisionShape2D
@onready var animation_player: AnimationPlayer = $AnimationPlayer
@onready var attack_hitbox: Area2D = $AttackHitbox
@onready var attack_hitbox_shape: CollisionShape2D = $AttackHitbox/CollisionShape2D

func _ready() -> void:
	_setup_collisions()

	if sprite and sprite.texture:
		sprite.scale = Vector2(0.5, 0.5)
	sprite.z_as_relative = false
	sprite.z_index = 10

func _setup_collisions() -> void:
	# 玩家碰撞体
	if collision_shape.shape == null:
		var circle = CircleShape2D.new()
		circle.radius = 12.0
		collision_shape.shape = circle

	# 攻击判定盒碰撞体 - 始终初始化为正确形状
	var rect = RectangleShape2D.new()
	rect.size = Vector2(24, 24)
	attack_hitbox_shape.shape = rect
	attack_hitbox_shape.disabled = false
	attack_hitbox.monitoring = false

	# 连接攻击命中信号
	if not attack_hitbox.body_entered.is_connected(_on_attack_hit):
		attack_hitbox.body_entered.connect(_on_attack_hit)
	if not attack_hitbox.area_entered.is_connected(_on_attack_hit_area):
		attack_hitbox.area_entered.connect(_on_attack_hit_area)

## 获取鼠标相对于玩家的方向
func get_mouse_direction() -> Vector2:
	return (get_global_mouse_position() - global_position).normalized()

## 被状态机调用 - 执行近战攻击
func perform_melee_attack() -> void:
	var attack_dir = get_mouse_direction()
	facing_direction = attack_dir
	attack_hitbox.position = attack_dir * attack_range
	attack_hitbox.rotation = attack_dir.angle()
	attack_hitbox.monitoring = true

	if animation_player.has_animation("attack"):
		animation_player.play("attack")

	# 0.15秒后关闭攻击判定
	await get_tree().create_timer(0.15).timeout
	attack_hitbox.monitoring = false
	attack_hitbox.position = Vector2.ZERO

## 攻击命中敌人
func _on_attack_hit(body: Node2D) -> void:
	if body.has_method("take_damage"):
		body.take_damage(attack_damage)

func _on_attack_hit_area(area: Area2D) -> void:
	if area.has_method("take_damage"):
		area.take_damage(attack_damage)

## 被敌人攻击时调用（供敌人和技能调用）
func take_damage(amount: int) -> void:
	print("🩸 玩家受到伤害: ", amount)
	# TODO: 后续接入血量和受伤动画

## 被状态机调用 - 释放技能
func cast_skill() -> void:
	if skill_scene == null:
		return

	var skill_dir = get_mouse_direction()
	facing_direction = skill_dir

	var skill_instance = skill_scene.instantiate() as Node2D
	get_tree().current_scene.add_child(skill_instance)

	skill_instance.global_position = global_position + skill_dir * 20.0
	if skill_instance.has_method("set_direction"):
		skill_instance.set_direction(skill_dir)

	if animation_player.has_animation("skill"):
		animation_player.play("skill")

Content of res://entities/player/states/idle.gd:
extends State
class_name PlayerIdleState

func enter() -> void:
	# 停止移动
	if entity is CharacterBody2D:
		entity.velocity = Vector2.ZERO

func physics_update(_delta: float) -> void:
	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	if input_dir.length() > 0.05:
		print("🔍 Idle: 检测到移动输入! input_dir=", input_dir)
		transitioned.emit(self, "move")
		return

	if Input.is_action_just_pressed("dodge"):
		print("🔍 Idle: 检测到闪避输入!")
		transitioned.emit(self, "dodge")
		return

	if Input.is_action_just_pressed("attack"):
		print("🔍 Idle: 检测到攻击输入!")
		transitioned.emit(self, "attack")
		return

	if Input.is_action_just_pressed("skill"):
		print("🔍 Idle: 检测到技能输入!")
		transitioned.emit(self, "skill")
		return

Content of res://entities/player/states/dodge.gd:
extends State
class_name PlayerDodgeState

@export var dodge_duration: float = 0.35
@export var dodge_speed: float = 600.0
var dodge_timer: float = 0.0
var dodge_direction: Vector2 = Vector2.RIGHT

func enter() -> void:
	dodge_timer = 0.0
	# 使用移动方向闪避，如果没有方向则使用朝向
	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")
	dodge_direction = input_dir if input_dir.length() > 0.1 else entity.facing_direction
	dodge_direction = dodge_direction.normalized()

func physics_update(delta: float) -> void:
	dodge_timer += delta

	# 闪避过程中不可控移动
	entity.velocity = dodge_direction * dodge_speed
	entity.move_and_slide()

	if dodge_timer >= dodge_duration:
		transitioned.emit(self, "idle")

