class_name EnemyIdleState

func physics_update(_delta: float) -> void:
	if not entity.player:
		return

	var dist = entity.distance_to_player()

	# 玩家在侦测范围内 → 追击
	if dist <= entity.detect_range:
		transitioned.emit(self, "chase")
"}

{"path": "res://entities/enemy/states/chase.gd", "content": "extends State
class_name EnemyChaseState

func enter() -> void:
	pass

func physics_update(_delta: float) -> void:
	if not entity.player:
		transitioned.emit(self, "idle")
		return

	var dist = entity.distance_to_player()

	# 进入攻击范围 → 攻击
	if dist <= entity.attack_range:
		transitioned.emit(self, "attack")
		return

	# 超出侦测范围 → 放弃
	if dist > entity.detect_range * 1.5:
		transitioned.emit(self, "idle")
		return

	# 向玩家移动
	var dir = entity.get_player_direction()
	entity.velocity = dir * entity.move_speed
	entity.move_and_slide()
"}

{"path": "res://entities/enemy/states/attack.gd", "content": "extends State
class_name EnemyAttackState

var attack_timer: float = 0.0

func enter() -> void:
	attack_timer = 0.0
	entity.velocity = Vector2.ZERO
	# 立即攻击一次
	entity.perform_attack()

func physics_update(delta: float) -> void:
	if not entity.player:
		transitioned.emit(self, "idle")
		return

	attack_timer += delta
	var dist = entity.distance_to_player()

	# 玩家跑远了 → 继续追
	if dist > entity.attack_range * 1.5:
		transitioned.emit(self, "chase")
		return

	# 攻击冷却到了 → 再打一次
	if attack_timer >= entity.attack_cooldown:
		attack_timer = 0.0
		entity.perform_attack()
"}

